#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

const SCSS_DIR = path.join(__dirname, 'scss');

// Standard gradation-05 through gradation-09 (same for ALL themes)
const STANDARD_GRADATIONS = [
  '--gradation-05: linear-gradient(145deg, #fef3c7 0%, #fbbf24 30%, #f59e0b 60%, #d97706 100%);',
  '--gradation-06: linear-gradient(145deg, #fecdd3 0%, #f43f5e 30%, #e11d48 60%, #be123c 100%);',
  '--gradation-07: linear-gradient(318.93deg, var(--gradient-01) 11.44%, var(--gradient-02) 90.56%);',
  '--gradation-08: linear-gradient(145.85deg, #d1d5db 10.23%, #6b7280 93.6%);',
  '--gradation-09: conic-gradient(from 0deg, var(--gradient-09) 0%, var(--gradient-09) 70%, var(--gradient-10) 80%, #ffffff 85%, var(--gradient-10) 90%, var(--gradient-09) 100%);',
];

// Skip these existing themes
const SKIP_THEMES = ['tc_001-sp', 'tc_011-fw8'];

// Neutral variable order
const NEUTRAL_ORDER = [0, 50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 1000];

// Category definitions for ordering and grouping
const CATEGORIES = [
  { prefix: 'primary', count: 10, pad: 2 },
  { prefix: 'secondary', count: 10, pad: 2 },
  { prefix: 'neutral', custom: true },
  { prefix: 'emotional', count: 10, pad: 2 },
  { prefix: 'opacity', count: 10, pad: 2 },
  { prefix: 'gradient', count: 16, pad: 2 },
  { prefix: 'gradation', custom: true },
];

function parseVars(rawStr) {
  // Parse semicolon-separated CSS variable definitions
  const vars = {};
  const parts = rawStr.split(';').map(s => s.trim()).filter(Boolean);
  for (const part of parts) {
    const match = part.match(/^(--[\w-]+):\s*(.+)$/);
    if (match) {
      vars[match[1]] = match[2].trim();
    }
  }
  return vars;
}

function generateFile(theme) {
  const vars = parseVars(theme.base);
  const gradVars = parseVars(theme.gradation);

  // Merge gradation vars into vars
  Object.assign(vars, gradVars);

  const lines = [':root,', 'body[data-theme="dark"] {'];

  let firstCategory = true;

  for (const cat of CATEGORIES) {
    const catLines = [];

    if (cat.prefix === 'neutral') {
      for (const n of NEUTRAL_ORDER) {
        const key = `--neutral-${n}`;
        if (vars[key] !== undefined) {
          catLines.push(`  ${key}: ${vars[key]};`);
        }
      }
    } else if (cat.prefix === 'gradation') {
      // gradation-01 to 04 from theme data
      for (let i = 1; i <= 4; i++) {
        const key = `--gradation-${String(i).padStart(2, '0')}`;
        if (vars[key] !== undefined) {
          catLines.push(`  ${key}: ${vars[key]};`);
        }
      }
      // gradation-05 to 09 standard
      for (const line of STANDARD_GRADATIONS) {
        catLines.push(`  ${line}`);
      }
    } else {
      const count = cat.count || 10;
      const pad = cat.pad || 2;
      for (let i = 1; i <= count; i++) {
        const key = `--${cat.prefix}-${String(i).padStart(pad, '0')}`;
        if (vars[key] !== undefined) {
          catLines.push(`  ${key}: ${vars[key]};`);
        }
      }
    }

    if (catLines.length > 0) {
      if (!firstCategory) {
        lines.push('');
      }
      lines.push(...catLines);
      firstCategory = false;
    }
  }

  lines.push('}');
  return lines.join('\n') + '\n';
}

