// ============================================================
// MAIN
// ============================================================

let created = 0;
let skipped = 0;

for (const theme of themes) {
  if (SKIP_THEMES.includes(theme.folder)) {
    console.log(`SKIP (existing): ${theme.folder}`);
    skipped++;
    continue;
  }

  const dir = path.join(SCSS_DIR, theme.folder);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }

  const content = generateFile(theme);
  const filePath = path.join(dir, '_baseColor.scss');
  fs.writeFileSync(filePath, content, 'utf8');
  console.log(`CREATED: ${filePath}`);
  created++;
}

